EMBEDDED_APP_ICON_ICO_BASE64 = """"""
EMBEDDED_APP_ICON_PNG_BASE64 = """"""


def get_desktop_dir() -> Path:
    home = Path.home()
    desktop = home / "Desktop"
    if desktop.exists():
        return desktop
    return home


def write_embedded_icon_ico(output_path: Path) -> Path:
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    output_path.write_bytes(base64.b64decode(EMBEDDED_APP_ICON_ICO_BASE64.encode("ascii")))
    return output_path

def get_embedded_icon_png_bytes() -> bytes:
    return base64.b64decode(EMBEDDED_APP_ICON_PNG_BASE64.encode("ascii"))



def sanitize_filename(name: str) -> str:
    cleaned = re.sub(r'[\\/:*?"<>|]+', "_", name).strip()
    cleaned = cleaned.replace("\n", " ").replace("\r", " ")
    cleaned = re.sub(r"\s+", " ", cleaned)
    return cleaned[:120] or "task"


def parse_api_keys(raw_text: str) -> list[str]:
    if not raw_text:
        return []
    parts = re.split(r"[\n,;]+", raw_text)
    keys: list[str] = []
    seen: set[str] = set()
    for part in parts:
        key = part.strip()
        if not key or key in seen:
            continue
        seen.add(key)
        keys.append(key)
    return keys


def format_elapsed(seconds: float) -> str:
    seconds = max(0, int(seconds))
    h, rem = divmod(seconds, 3600)
    m, s = divmod(rem, 60)
    return f"{h:02d}:{m:02d}:{s:02d}"


def now_text() -> str:
    return time.strftime("%Y-%m-%d %H:%M:%S")


def prompt_default_note(prompt: str) -> str:
    prompt = (prompt or "").strip()
    if not prompt:
        return "未命名"
    compact = re.sub(r"\s+", " ", prompt)
    return compact[:5]


def prompt_snippet(prompt: str, limit: int = 24) -> str:
    prompt = re.sub(r"\s+", " ", (prompt or "").strip())
    if len(prompt) <= limit:
        return prompt
    return prompt[:limit] + "..."


class ApiRateLimitError(RuntimeError):
    pass


class AdaptiveRequestGate:
    def __init__(self, base_interval: float, max_interval: float):
        self.base_interval = float(base_interval)
        self.max_interval = float(max_interval)
        self.current_interval = float(base_interval)
        self.next_allowed_time = 0.0
        self.lock = threading.Lock()

    def wait_turn(self, stop_event: threading.Event) -> None:
        while not stop_event.is_set():
            with self.lock:
                now = time.monotonic()
                wait_seconds = self.next_allowed_time - now
                if wait_seconds <= 0:
                    self.next_allowed_time = now + self.current_interval
                    return
            time.sleep(min(max(wait_seconds, 0.01), 0.2))

    def on_success(self) -> None:
        with self.lock:
            self.current_interval = max(self.base_interval, self.current_interval * 0.92)

    def on_rate_limit(self) -> float:
        with self.lock:
            self.current_interval = min(self.max_interval, max(self.base_interval, self.current_interval * 1.5))
            self.next_allowed_time = max(self.next_allowed_time, time.monotonic() + self.current_interval)
            return self.current_interval


class RunningHubClient:
    def __init__(self, api_key: str):
        self.api_key = api_key.strip()
        self.session = requests.Session()
        self.session.headers.update({"Authorization": f"Bearer {self.api_key}"})

    def _json_headers(self) -> dict:
        return {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
        }

    @staticmethod
    def _is_rate_limit_payload(data: dict) -> bool:
        error_code = str(data.get("errorCode") or "").strip()
        error_message = str(data.get("errorMessage") or "").lower()
        return error_code == "1003" or "rate limit" in error_message or "请求频率超限" in error_message

    def upload_image(self, image_path: Path) -> str:
        with image_path.open("rb") as f:
            files = {"file": (image_path.name, f, "application/octet-stream")}
            response = self.session.post(UPLOAD_URL, files=files, timeout=REQUEST_TIMEOUT)
        self._raise_for_status(response, "上传图片失败")
        data = response.json()
        if self._is_rate_limit_payload(data):
            raise ApiRateLimitError(f"上传图片触发限速：{data}")
        if data.get("code") != 0 or not data.get("data", {}).get("download_url"):
            raise RuntimeError(f"上传图片失败：{data}")
        return data["data"]["download_url"]

    def submit_edit_task(self, image_urls: list[str], prompt: str, aspect_ratio: str, resolution: str, model_name: str) -> str:
        payload = {
            "imageUrls": image_urls,
            "prompt": prompt,
            "aspectRatio": aspect_ratio,
        }
        if model_name == MODEL_GPT_IMAGE_2:
            submit_url = SUBMIT_EDIT_URL_GPT_IMAGE_2
            error_prefix = "提交 GPT-image 2.0 图生图任务失败"
        elif model_name == MODEL_NANOBANANA_V2:
            payload["resolution"] = resolution
            submit_url = SUBMIT_EDIT_URL_V2
            error_prefix = "提交 NanoBanana V2 图生图任务失败"
        else:
            payload["resolution"] = resolution
            submit_url = SUBMIT_EDIT_URL_PRO
            error_prefix = "提交 NanoBanana Pro 图生图任务失败"

        response = self.session.post(
            submit_url,
            headers=self._json_headers(),
            data=json.dumps(payload, ensure_ascii=False),
            timeout=REQUEST_TIMEOUT,
        )
        self._raise_for_status(response, error_prefix)
        data = response.json()
        if self._is_rate_limit_payload(data):
            raise ApiRateLimitError(f"{error_prefix}：{data}")
        task_id = data.get("taskId")
        if not task_id:
            raise RuntimeError(f"{error_prefix}，未返回 taskId：{data}")
        return task_id

    def submit_text_task(self, prompt: str, aspect_ratio: str, resolution: str, model_name: str) -> str:
        payload = {
            "prompt": prompt,
            "aspectRatio": aspect_ratio,
        }
        if model_name == MODEL_GPT_IMAGE_2:
            submit_url = SUBMIT_TEXT_URL_GPT_IMAGE_2
            error_prefix = "提交 GPT-image 2.0 文生图任务失败"
        elif model_name == MODEL_NANOBANANA_V2:
            payload["resolution"] = resolution
            submit_url = SUBMIT_TEXT_URL_V2
            error_prefix = "提交 NanoBanana V2 文生图任务失败"
        else:
            payload["resolution"] = resolution
            submit_url = SUBMIT_TEXT_URL_PRO
            error_prefix = "提交 NanoBanana Pro 文生图任务失败"
        response = self.session.post(
            submit_url,
            headers=self._json_headers(),
            data=json.dumps(payload, ensure_ascii=False),
            timeout=REQUEST_TIMEOUT,
        )
        self._raise_for_status(response, error_prefix)
        data = response.json()
        if self._is_rate_limit_payload(data):
            raise ApiRateLimitError(f"{error_prefix}：{data}")
        task_id = data.get("taskId")
        if not task_id:
            raise RuntimeError(f"{error_prefix}，未返回 taskId：{data}")
        return task_id

    def query_task(self, task_id: str) -> dict:
        payload = {"taskId": task_id}
        response = self.session.post(
            QUERY_URL,
            headers=self._json_headers(),
            data=json.dumps(payload, ensure_ascii=False),
            timeout=REQUEST_TIMEOUT,
        )
        self._raise_for_status(response, "查询任务失败")
        data = response.json()
        if self._is_rate_limit_payload(data):
            raise ApiRateLimitError(f"查询任务触发限速：{data}")
        return data

    def query_account_status(self) -> dict:
        payload = {"apikey": self.api_key}
        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
            "Host": "www.runninghub.cn",
        }
        response = self.session.post(
            ACCOUNT_STATUS_URL,
            headers=headers,
            data=json.dumps(payload, ensure_ascii=False),
            timeout=REQUEST_TIMEOUT,
        )
        self._raise_for_status(response, "获取账户信息失败")
        data = response.json()
        if int(data.get("code", -1)) != 0:
            raise RuntimeError(f"获取账户信息失败：{data}")
        return data.get("data") or {}

    @staticmethod
    def _raise_for_status(response: requests.Response, prefix: str) -> None:
        if response.status_code == 429:
            raise ApiRateLimitError(f"{prefix}：HTTP 429 - {response.text.strip()}")
        if response.status_code >= 400:
            raise RuntimeError(f"{prefix}：HTTP {response.status_code} - {response.text.strip()}")


class SettingsDialog(tk.Toplevel):
    def __init__(self, master: "App") -> None:
        super().__init__(master)
        self.title("设置")
        self.transient(master)
        self.resizable(False, False)
        self.grab_set()
        self.master_app = master
        self.remember_var = tk.BooleanVar(value=master.remember_api_key_var.get())
        self.max_retry_var = tk.StringVar(value=master.max_retry_var.get())
        self.delete_task_delete_image_var = tk.BooleanVar(value=master.delete_task_delete_image_var.get())
        self.drop_add_to_folder_var = tk.BooleanVar(value=master.drop_add_to_folder_var.get())
        self.show_plain = False

        self.columnconfigure(1, weight=1)

        ttk.Label(self, text="API Keys（每行一个）").grid(row=0, column=0, sticky="nw", padx=12, pady=(12, 8))
        self.api_text = tk.Text(self, width=56, height=5, wrap="none")
        self.api_text.grid(row=0, column=1, columnspan=2, sticky="ew", padx=(0, 12), pady=(12, 8))
        self.api_text.insert("1.0", master.api_keys_raw_var.get() or master.api_key_var.get())

        ttk.Checkbutton(
            self,
            text="记住 API Key（保存在 exe 同目录配置文件中）",
            variable=self.remember_var,
        ).grid(row=1, column=0, columnspan=3, sticky="w", padx=12, pady=(0, 8))

        ttk.Label(self, text="最大重试次数").grid(row=2, column=0, sticky="w", padx=12, pady=(0, 8))
        ttk.Entry(self, textvariable=self.max_retry_var, width=12).grid(row=2, column=1, sticky="w", padx=(0, 8), pady=(0, 8))

        ttk.Checkbutton(
            self,
            text="任务列表删除表示删除图片",
            variable=self.delete_task_delete_image_var,
        ).grid(row=3, column=0, columnspan=3, sticky="w", padx=12, pady=(0, 8))

        ttk.Checkbutton(
            self,
            text="源图预览拖入时，自动添加到当前图片文件夹（无文件夹时自动在桌面创建时间戳文件夹）",
            variable=self.drop_add_to_folder_var,
        ).grid(row=4, column=0, columnspan=3, sticky="w", padx=12, pady=(0, 8))

        ttk.Label(
            self,
            text="说明：支持填写多个 API Key，会自动统计所有 Key 的总余额。实际生成默认使用第一个 Key。",
            foreground="#666666",
        ).grid(row=5, column=0, columnspan=3, sticky="w", padx=12, pady=(0, 12))

        btns = ttk.Frame(self)
        btns.grid(row=6, column=0, columnspan=3, sticky="e", padx=12, pady=(0, 12))
        ttk.Button(btns, text="保存", command=self.save).pack(side="left", padx=(0, 8))
        ttk.Button(btns, text="取消", command=self.destroy).pack(side="left")

        self.bind("<Escape>", lambda _e: self.destroy())
        self.bind("<Return>", lambda _e: self.save())
        self.api_text.focus_set()
        self.update_idletasks()
        self.geometry(f"+{master.winfo_rootx() + 120}+{master.winfo_rooty() + 120}")

    def save(self) -> None:
        raw_text = self.api_text.get("1.0", "end").strip()
        keys = parse_api_keys(raw_text)
        if not keys:
            messagebox.showwarning(APP_TITLE, "请至少填写一个 API Key。", parent=self)
            return
        try:
            max_retry = int(self.max_retry_var.get().strip() or DEFAULT_MAX_TASK_RETRY)
            if max_retry < 0:
                raise ValueError
        except ValueError:
            messagebox.showwarning(APP_TITLE, "最大重试次数必须是大于等于 0 的整数。", parent=self)
            return

        self.master_app.api_keys_raw_var.set("\n".join(keys))
        self.master_app.api_key_var.set(keys[0])
        self.master_app.remember_api_key_var.set(bool(self.remember_var.get()))
        self.master_app.max_retry_var.set(str(max_retry))
        self.master_app.delete_task_delete_image_var.set(bool(self.delete_task_delete_image_var.get()))
        self.master_app.drop_add_to_folder_var.set(bool(self.drop_add_to_folder_var.get()))
        self.master_app.save_ui_config_only()
        self.master_app.refresh_settings_state_label()
        self.master_app.refresh_balance_async()
        drop_mode = "拖入自动入当前图片文件夹" if self.drop_add_to_folder_var.get() else "拖入仅作为单图预览"
        self.master_app.append_log(f"设置已保存。共 {len(keys)} 个 API Key，最大重试次数：{max_retry}，{drop_mode}。")
        self.destroy()


class PromptEditDialog(tk.Toplevel):
    def __init__(self, master: "App", entry: Optional[dict] = None):
        super().__init__(master)
        self.master_app = master
        self.entry = dict(entry) if entry else None
        self.title("提示词编辑")
        self.transient(master)
        self.grab_set()
        self.geometry(f"900x560+{master.winfo_rootx() + 80}+{master.winfo_rooty() + 80}")

        self.columnconfigure(0, weight=1)
        self.rowconfigure(1, weight=1)

        top = ttk.Frame(self, padding=12)
        top.grid(row=0, column=0, sticky="ew")
        top.columnconfigure(1, weight=1)
        ttk.Label(top, text="备注").grid(row=0, column=0, sticky="w")
        self.note_var = tk.StringVar(value=(self.entry or {}).get("note", ""))
        ttk.Entry(top, textvariable=self.note_var).grid(row=0, column=1, sticky="ew", padx=(8, 0))

        self.prompt_text = tk.Text(self, wrap="word", font=("Microsoft YaHei UI", 10))
        self.prompt_text.grid(row=1, column=0, sticky="nsew", padx=12, pady=(0, 12))
        self.prompt_text.insert("1.0", (self.entry or {}).get("prompt", ""))

        btns = ttk.Frame(self, padding=(12, 0, 12, 12))
        btns.grid(row=2, column=0, sticky="e")
        ttk.Button(btns, text="保存", command=self.on_save).pack(side="left", padx=(0, 8))
        ttk.Button(btns, text="应用到主页", command=self.on_apply).pack(side="left", padx=(0, 8))
        if self.entry:
            ttk.Button(btns, text="删除", command=self.on_delete).pack(side="left", padx=(0, 8))
        ttk.Button(btns, text="取消", command=self.destroy).pack(side="left")
        self.bind("<Escape>", lambda _e: self.destroy())

    def _collect(self) -> Optional[dict]:
        prompt = self.prompt_text.get("1.0", "end").strip()
        if not prompt:
            messagebox.showwarning(APP_TITLE, "提示词不能为空。", parent=self)
            return None
        note = self.note_var.get().strip() or prompt_default_note(prompt)
        data = dict(self.entry) if self.entry else {}
        data.update({
            "id": data.get("id") or uuid.uuid4().hex,
            "note": note,
            "prompt": prompt,
            "last_used": data.get("last_used", ""),
            "created_at": data.get("created_at") or now_text(),
        })
        return data

    def on_save(self) -> None:
        data = self._collect()
        if not data:
            return
        self.master_app.save_managed_prompt(data)
        self.destroy()

    def on_apply(self) -> None:
        data = self._collect()
        if not data:
            return
        self.master_app.apply_prompt_to_main(data["prompt"])
        self.note_var.set(data["note"])

    def on_delete(self) -> None:
        if self.entry and messagebox.askyesno(APP_TITLE, "确定删除这条固定提示词吗？", parent=self):
            self.master_app.delete_managed_prompt(self.entry.get("id"))
            self.destroy()


class PromptManagerDialog(tk.Toplevel):
    def __init__(self, master: "App"):
        super().__init__(master)
        self.master_app = master
        self.title("提示词管理")
        self.transient(master)
        self.geometry(f"960x600+{master.winfo_rootx() + 50}+{master.winfo_rooty() + 50}")
        self.columnconfigure(0, weight=1)
        self.rowconfigure(1, weight=1)

        top = ttk.Frame(self, padding=12)
        top.grid(row=0, column=0, sticky="ew")
        ttk.Button(top, text="新增提示词", command=self.add_new).pack(side="left")
        ttk.Label(top, text="单击下方条目可编辑；按最后使用时间排序。", foreground="#666").pack(side="left", padx=(12, 0))

        body = ttk.Frame(self, padding=(12, 0, 12, 12))
        body.grid(row=1, column=0, sticky="nsew")
        body.columnconfigure(0, weight=1)
        body.rowconfigure(0, weight=1)
        self.canvas = tk.Canvas(body, highlightthickness=0)
        self.canvas.grid(row=0, column=0, sticky="nsew")
        self.scrollbar = ttk.Scrollbar(body, orient="vertical", command=self.canvas.yview)
        self.scrollbar.grid(row=0, column=1, sticky="ns")
        self.canvas.configure(yscrollcommand=self.scrollbar.set)
        self.inner = ttk.Frame(self.canvas)
        self.window_id = self.canvas.create_window((0, 0), window=self.inner, anchor="nw")
        self.inner.bind("<Configure>", lambda _e: self.canvas.configure(scrollregion=self.canvas.bbox("all")))
        self.canvas.bind("<Configure>", lambda e: self.canvas.itemconfigure(self.window_id, width=e.width))
        self.refresh_list()

    def add_new(self) -> None:
        PromptEditDialog(self.master_app, None)
        self.after(200, self.refresh_list)

    def refresh_list(self) -> None:
        for child in self.inner.winfo_children():
            child.destroy()
        entries = self.master_app.get_sorted_prompt_templates()
        if not entries:
            ttk.Label(self.inner, text="暂无固定提示词", foreground="#666").pack(anchor="w", pady=8)
            return
        for entry in entries:
            row = tk.Frame(self.inner, bd=1, relief="solid", bg="white")
            row.pack(fill="x", pady=6, padx=2)
            row.grid_columnconfigure(0, weight=1)

            meta = f"{entry.get('note', '')}｜最后使用：{entry.get('last_used', '未使用') or '未使用'}"
            title = ttk.Label(row, text=meta, background="white")
            title.grid(row=0, column=0, sticky="w", padx=10, pady=(8, 2))

            snippet = ttk.Label(row, text=prompt_snippet(entry.get('prompt', ''), 70), foreground="#555", background="white")
            snippet.grid(row=1, column=0, sticky="w", padx=10, pady=(0, 8))

            ttk.Button(row, text="删除", width=8, command=lambda eid=entry.get('id'): self._delete(eid)).grid(row=0, column=1, rowspan=2, padx=10, pady=8)

            for widget in (row, title, snippet):
                widget.bind("<Button-1>", lambda _e, item=entry: self._edit(item))

    def _edit(self, item: dict) -> None:
        PromptEditDialog(self.master_app, item)
        self.after(200, self.refresh_list)

    def _delete(self, template_id: str) -> None:
        self.master_app.delete_managed_prompt(template_id)
        self.refresh_list()


class PromptHistoryDialog(tk.Toplevel):
    def __init__(self, master: "App"):
        super().__init__(master)
        self.master_app = master
        self.title("提示词历史记录")
        self.transient(master)
        self.geometry(f"980x560+{master.winfo_rootx() + 60}+{master.winfo_rooty() + 60}")
        self.columnconfigure(0, weight=1)
        self.rowconfigure(0, weight=1)
        columns = ("note", "last_used", "snippet")
        self.tree = ttk.Treeview(self, columns=columns, show="headings")
        self.tree.heading("note", text="备注")
        self.tree.heading("last_used", text="最后使用时间")
        self.tree.heading("snippet", text="提示词前部分内容")
        self.tree.column("note", width=120, anchor="w")
        self.tree.column("last_used", width=160, anchor="center")
        self.tree.column("snippet", width=640, anchor="w")
        self.tree.grid(row=0, column=0, sticky="nsew", padx=12, pady=12)
        scroll = ttk.Scrollbar(self, orient="vertical", command=self.tree.yview)
        scroll.grid(row=0, column=1, sticky="ns", pady=12)
        self.tree.configure(yscrollcommand=scroll.set)
        bottom = ttk.Frame(self, padding=(12, 0, 12, 12))
        bottom.grid(row=1, column=0, columnspan=2, sticky="e")
        ttk.Button(bottom, text="应用到主页", command=self.apply_selected).pack(side="left", padx=(0, 8))
        ttk.Button(bottom, text="删除记录", command=self.delete_selected).pack(side="left", padx=(0, 8))
        ttk.Button(bottom, text="关闭", command=self.destroy).pack(side="left")
        self.item_map = {}
        self.refresh_list()
        self.tree.bind("<Double-1>", lambda _e: self.apply_selected())

    def refresh_list(self) -> None:
        self.item_map.clear()
        for row in self.tree.get_children():
            self.tree.delete(row)
        for entry in self.master_app.get_sorted_prompt_history():
            iid = self.tree.insert("", "end", values=(entry.get("note", ""), entry.get("last_used", ""), prompt_snippet(entry.get("prompt", ""), 90)))
            self.item_map[iid] = entry

    def apply_selected(self) -> None:
        sel = self.tree.selection()
        if not sel:
            return
        entry = self.item_map.get(sel[0])
        if entry:
            self.master_app.apply_prompt_to_main(entry.get("prompt", ""))

    def delete_selected(self) -> None:
        sel = self.tree.selection()
        if not sel:
            return
        entry = self.item_map.get(sel[0])
        if entry:
            self.master_app.delete_history_prompt(entry.get("prompt", ""))
            self.refresh_list()


class ZoomableImagePane(ttk.Frame):
    def __init__(self, master: tk.Misc, title: str, image_path: Path):
        super().__init__(master)
        self.image_path = Path(image_path)
        self.title = title
        self.columnconfigure(0, weight=1)
        self.rowconfigure(1, weight=1)
        ttk.Label(self, text=title).grid(row=0, column=0, pady=(0, 8))
        self.canvas = tk.Canvas(self, bg="#111111", highlightthickness=0, cursor="fleur")
        self.canvas.grid(row=1, column=0, sticky="nsew")
        self.canvas.bind("<Configure>", self._on_configure)
        self.canvas.bind("<ButtonPress-1>", self._on_press)
        self.canvas.bind("<B1-Motion>", self._on_drag)
        self.canvas.bind("<Control-MouseWheel>", self._on_zoom)
        self.canvas.bind("<Control-Button-4>", self._on_zoom_linux_up)
        self.canvas.bind("<Control-Button-5>", self._on_zoom_linux_down)
        self.original = ImageOps.exif_transpose(Image.open(self.image_path))
        self.base_scale = 1.0
        self.zoom_scale = 1.0
        self.offset_x = 0
        self.offset_y = 0
        self.drag_start = None
        self.imgtk = None
        self.image_id = None
        self.last_size = (0, 0)
        self._pending_redraw = None

    def _on_configure(self, _event=None) -> None:
        self.fit_image()

    def fit_image(self) -> None:
        cw = max(100, self.canvas.winfo_width())
        ch = max(100, self.canvas.winfo_height())
        self.base_scale = min(cw / self.original.width, ch / self.original.height)
        self.base_scale = max(self.base_scale, 0.05)
        self.zoom_scale = 1.0
        self.offset_x = 0
        self.offset_y = 0
        self.redraw(force=True)

    def redraw(self, force: bool = False) -> None:
        cw = max(100, self.canvas.winfo_width())
        ch = max(100, self.canvas.winfo_height())
        scale = self.base_scale * self.zoom_scale
        w = max(1, int(self.original.width * scale))
        h = max(1, int(self.original.height * scale))
        if force or self.last_size != (w, h) or self.image_id is None:
            img = self.original.resize((w, h), Image.LANCZOS)
            self.imgtk = ImageTk.PhotoImage(img)
            if self.image_id is None:
                self.image_id = self.canvas.create_image(0, 0, image=self.imgtk, anchor="center", tags="img")
            else:
                self.canvas.itemconfigure(self.image_id, image=self.imgtk)
            self.last_size = (w, h)
        cx = cw // 2 + int(self.offset_x)
        cy = ch // 2 + int(self.offset_y)
        self.canvas.coords(self.image_id, cx, cy)

    def _schedule_redraw(self, force: bool = False) -> None:
        if self._pending_redraw is not None:
            try:
                self.after_cancel(self._pending_redraw)
            except Exception:
                pass
        self._pending_redraw = self.after(1, lambda: self._finish_scheduled_redraw(force))

    def _finish_scheduled_redraw(self, force: bool = False) -> None:
        self._pending_redraw = None
        self.redraw(force=force)

    def _on_press(self, event) -> None:
        self.drag_start = (event.x, event.y)

    def _on_drag(self, event) -> None:
        if not self.drag_start or self.image_id is None:
            return
        dx = event.x - self.drag_start[0]
        dy = event.y - self.drag_start[1]
        self.offset_x += dx
        self.offset_y += dy
        self.drag_start = (event.x, event.y)
        self.canvas.move(self.image_id, dx, dy)

    def _zoom_common(self, factor: float) -> None:
        self.zoom_scale = min(15.0, max(0.1, self.zoom_scale * factor))
        self._schedule_redraw(force=True)

    def _on_zoom(self, event) -> None:
        self._zoom_common(1.1 if event.delta > 0 else 0.9)

    def _on_zoom_linux_up(self, _event) -> None:
        self._zoom_common(1.1)

    def _on_zoom_linux_down(self, _event) -> None:
        self._zoom_common(0.9)


class ImagePreviewWindow(tk.Toplevel):
    def __init__(self, master: tk.Misc, images: list[tuple[str, Path]], regenerate_callback=None):
        super().__init__(master)
        self.title("图片预览")
        self.configure(bg="black")
        self.images = images
        self.regenerate_callback = regenerate_callback
        self.attributes("-fullscreen", True)
        self.protocol("WM_DELETE_WINDOW", self.close_window)
        for i in range(max(1, len(images))):
            self.columnconfigure(i, weight=1)
        self.rowconfigure(0, weight=1)
        self._bound_sequences = ["<KeyPress-q>", "<KeyPress-Q>", "<KeyPress-Escape>", "<KeyPress-r>", "<KeyPress-R>"]
        for seq in self._bound_sequences:
            self.bind_all(seq, self._handle_key)
        self.after(50, self.render)
        self.after(100, self._force_focus)

    def _force_focus(self) -> None:
        try:
            self.lift()
            self.focus_force()
        except Exception:
            pass

    def _handle_key(self, event) -> None:
        key = str(event.keysym).lower()
        if key in {"q", "escape"}:
            self.close_window()
        elif key == "r" and callable(self.regenerate_callback):
            callback = self.regenerate_callback
            self.close_window()
            try:
                self.master.after(80, callback)
            except Exception:
                callback()

    def close_window(self) -> None:
        for seq in self._bound_sequences:
            try:
                self.unbind_all(seq)
            except Exception:
                pass
        self.destroy()

    def render(self) -> None:
        for idx, (title, path) in enumerate(self.images):
            frame = ZoomableImagePane(self, title, path)
            frame.grid(row=0, column=idx, sticky="nsew", padx=10, pady=10)
        tip = tk.Label(
            self,
            text="快捷键：Q/Esc 退出｜R 重新生成｜Ctrl+滚轮 缩放｜拖动图片可移动",
            bg="black",
            fg="white",
        )
        tip.place(relx=0.5, rely=0.985, anchor="s")


