    def get_generation_count(self) -> int:
        try:
            value = int(self.generation_count_var.get().strip() or DEFAULT_GENERATION_COUNT)
            if value <= 0:
                raise ValueError
            return value
        except ValueError as exc:
            raise ValueError("生成数量必须是大于等于 1 的整数。") from exc

    def get_max_retry_count(self) -> int:
        try:
            value = int(self.max_retry_var.get().strip() or DEFAULT_MAX_TASK_RETRY)
            if value < 0:
                raise ValueError
            return value
        except ValueError as exc:
            raise ValueError("最大重试次数必须是大于等于 0 的整数。") from exc

